import React, { useState, useEffect } from 'react';
import axios from 'axios';
import StatsCard from '../../components/admin/StatsCard';
import './Dashboard.css';

const Dashboard = () => {
    const [stats, setStats] = useState({
        totalCars: 0,
        totalUsers: 0,
        totalTestDrives: 0,
        pendingReviews: 0,
        totalOrders: 0,
        totalRevenue: 0
    });
    const [recentTestDrives, setRecentTestDrives] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetchDashboardData();
    }, []);

    const fetchDashboardData = async () => {
        try {
            // Lấy số liệu thống kê
            const [carsRes, usersRes, testDrivesRes, ordersRes] = await Promise.all([
                axios.get('http://localhost:5000/api/cars'),
                axios.get('http://localhost:5000/api/admin/users'),
                axios.get('http://localhost:5000/api/admin/testdrives'),
                axios.get('http://localhost:5000/api/admin/orders')
            ]);

            const totalCars = (carsRes.data.data || carsRes.data).length;
            const totalUsers = usersRes.data.length;
            const totalTestDrives = testDrivesRes.data.length;
            
            // Tính tổng doanh thu
            const orders = ordersRes.data.orders || [];
            const totalRevenue = orders.reduce((sum, order) => sum + order.total_amount, 0);
            const totalOrders = orders.length;

            setStats({
                totalCars,
                totalUsers,
                totalTestDrives,
                pendingReviews: 0,
                totalOrders,
                totalRevenue
            });

            setRecentTestDrives(testDrivesRes.data.slice(0, 5));
            setLoading(false);
        } catch (error) {
            console.error('Lỗi tải dashboard:', error);
            setLoading(false);
        }
    };

    const formatPrice = (price) => {
        return price.toString().replace(/\B(?=(\d{3})+(?!\d))/g, '.') + ' ₫';
    };

    const formatDate = (dateString) => {
        return new Date(dateString).toLocaleDateString('vi-VN');
    };

    if (loading) return <div className="loading">Đang tải...</div>;

    return (
        <div className="dashboard">
            <h1>Dashboard</h1>
            
            {/* Stats Cards - Xếp ngang */}
            <div className="stats-grid">
                <StatsCard 
                    icon="🚗" 
                    title="Tổng số xe" 
                    value={stats.totalCars}
                    color="#3498db"
                />
                <StatsCard 
                    icon="👥" 
                    title="Người dùng" 
                    value={stats.totalUsers}
                    color="#27ae60"
                />
                <StatsCard 
                    icon="📅" 
                    title="Lịch lái thử" 
                    value={stats.totalTestDrives}
                    color="#f39c12"
                />
                <StatsCard 
                    icon="⭐" 
                    title="Đánh giá chờ" 
                    value={stats.pendingReviews}
                    color="#e74c3c"
                />
                <StatsCard 
                    icon="📦" 
                    title="Đơn hàng" 
                    value={stats.totalOrders}
                    color="#9b59b6"
                />
                <StatsCard 
                    icon="💰" 
                    title="Doanh thu" 
                    value={formatPrice(stats.totalRevenue)}
                    color="#1abc9c"
                />
            </div>

            {/* Recent Test Drives Table - Xếp ngang */}
            <div className="recent-section">
                <h2>Lịch lái thử gần đây</h2>
                <table className="admin-table">
                    <thead>
                        <tr>
                            <th>Người đặt</th>
                            <th>Xe</th>
                            <th>Ngày</th>
                            <th>Giờ</th>
                            <th>Trạng thái</th>
                            <th>Thao tác</th>
                        </tr>
                    </thead>
                    <tbody>
                        {recentTestDrives.length === 0 ? (
                            <tr>
                                <td colSpan="6" style={{ textAlign: 'center' }}>Chưa có lịch lái thử nào</td>
                            </tr>
                        ) : (
                            recentTestDrives.map(drive => (
                                <tr key={drive.id}>
                                    <td>{drive.fullname}</td>
                                    <td>{drive.car_name}</td>
                                    <td>{formatDate(drive.test_date)}</td>
                                    <td>{drive.test_time}</td>
                                    <td>
                                        <span className={`status-badge ${drive.status}`}>
                                            {drive.status === 'pending' ? '⏳ Chờ' :
                                             drive.status === 'confirmed' ? '✅ Đã xác nhận' :
                                             drive.status === 'completed' ? '✔️ Hoàn thành' : '❌ Đã hủy'}
                                        </span>
                                    </td>
                                    <td>
                                        <button className="btn-view">Chi tiết</button>
                                    </td>
                                </tr>
                            ))
                        )}
                    </tbody>
                </table>
            </div>
        </div>
    );
};

export default Dashboard;
